import React, { useState, useRef } from 'react';
import { Link } from 'react-router-dom';
import styles from './Header.module.css';
import logo from '../assets/images/logo.png';

const womenMegaMenu = {
  'READY TO WEAR': [
    { name: 'OUTERWEAR', link: '/collection/women?category=outerwear' },
    { name: 'JACKETS', link: '/collection/women?category=jackets' },
    { name: 'TOPS & T-SHIRTS', link: '/collection/women?category=tops' },
    { name: 'SHIRTS & BLOUSES', link: '/collection/women?category=shirts' },
    { name: 'KNITWEAR', link: '/collection/women?category=knitwear' },
    { name: 'DRESSES', link: '/collection/women?category=dresses' },
    { name: 'SKIRTS', link: '/collection/women?category=skirts' },
    { name: 'PANTS', link: '/collection/women?category=pants' },
    { name: 'SIGNATURE LEATHER', link: '/collection/women?category=signature-leather' },
    { name: 'ESSENTIAL', link: '/collection/women?category=essential' },
    { name: 'ALL', link: '/collection/women' },
  ],
  BAG: [
    { name: 'SINGULAR BAG', link: '/collection/women?category=bags&sub=singular' },
    { name: '21 LEATHER BUCKET BAG', link: '/collection/women?category=bags&sub=bucket' },
    { name: 'ALL', link: '/collection/women?category=bags' },
  ],
  SHOES: [
    { name: 'ALL', link: '/collection/women?category=shoes' },
  ],
  ACCESSORIES: [
    { name: 'ALL', link: '/collection/women?category=accessories' },
  ],
  'PREVIOUS SEASON': [
    { name: 'ALL', link: '/collection/women?category=previous' },
  ],
};

function Header() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [megaOpen, setMegaOpen] = useState(false);
  const timeoutRef = useRef(null);

  const navLeft = [
    { label: 'SHOP', key: 'shop' },
    { label: 'ABOUT', key: 'about' },
    { label: 'COLLECTIONS', key: 'collections' },
  ];
  const navRight = ['SEARCH', 'ACCOUNT', 'INQUIRY'];

  const handleMouseEnter = (key) => {
    if (key === 'shop') {
      clearTimeout(timeoutRef.current);
      setMegaOpen(true);
    }
  };

  const handleMouseLeave = () => {
    timeoutRef.current = setTimeout(() => setMegaOpen(false), 150);
  };

  const handleMegaEnter = () => {
    clearTimeout(timeoutRef.current);
  };

  const handleMegaLeave = () => {
    timeoutRef.current = setTimeout(() => setMegaOpen(false), 150);
  };

  return (
    <header className={styles.header}>
      <nav className={styles.nav}>
        {/* Desktop nav left */}
        <ul className={styles.navLeft}>
          {navLeft.map((item) => (
            <li
              key={item.key}
              onMouseEnter={() => handleMouseEnter(item.key)}
              onMouseLeave={handleMouseLeave}
            >
              <a href="#!" className={styles.navLink}>{item.label}</a>
            </li>
          ))}
        </ul>

        {/* Mobile hamburger */}
        <button
          className={styles.menuBtn}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Menu"
        >
          <svg width="18" height="12" viewBox="0 0 18 12" fill="none">
            <line y1="0.5" x2="18" y2="0.5" stroke="currentColor" />
            <line y1="5.5" x2="18" y2="5.5" stroke="currentColor" />
            <line y1="10.5" x2="18" y2="10.5" stroke="currentColor" />
          </svg>
        </button>

        <Link to="/" className={styles.logo}>
          <img src={logo} alt="RECTO" className={styles.logoImg} />
        </Link>

        {/* Desktop nav right */}
        <ul className={styles.navRight}>
          {navRight.map((item) => (
            <li key={item}>
              <a href="#!" className={styles.navLink}>{item}</a>
            </li>
          ))}
        </ul>

        {/* Mobile icons */}
        <div className={styles.mobileIcons}>
          <button className={styles.iconBtn} aria-label="Search">
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <circle cx="6.5" cy="6.5" r="5.5" stroke="currentColor" strokeWidth="1" />
              <line x1="10.5" y1="10.5" x2="15" y2="15" stroke="currentColor" strokeWidth="1" />
            </svg>
          </button>
          <button className={styles.iconBtn} aria-label="Cart">
            <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
              <path d="M3 4L4 14H12L13 4" stroke="currentColor" strokeWidth="1" />
              <path d="M5.5 4V3C5.5 1.5 6.5 0.5 8 0.5C9.5 0.5 10.5 1.5 10.5 3V4" stroke="currentColor" strokeWidth="1" />
            </svg>
          </button>
        </div>
      </nav>

      {/* Mega Menu */}
      <div
        className={`${styles.megaMenu} ${megaOpen ? styles.megaOpen : ''}`}
        onMouseEnter={handleMegaEnter}
        onMouseLeave={handleMegaLeave}
      >
        <div className={styles.megaInner}>
          {Object.entries(womenMegaMenu).map(([group, items]) => (
            <div key={group} className={styles.megaColumn}>
              <span className={styles.megaGroupTitle}>{group}</span>
              <ul className={styles.megaList}>
                {items.map((item) => (
                  <li key={item.name}>
                    <Link to={item.link} className={styles.megaLink} onClick={() => setMegaOpen(false)}>
                      {item.name}
                    </Link>
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>

      {/* Overlay */}
      {megaOpen && <div className={styles.megaOverlay} onClick={() => setMegaOpen(false)} />}
    </header>
  );
}

export default Header;
